              import java.time.temporal.ChronoUnit;
              import java.util.Calendar;
              import sailpoint.object.Filter;

              log.error("entered into the QueryOptions");

              log.error("   identity in HistoricaIdentityEvent_CheckReport ..."+value)

              queryOptions.add(Filter.or(Filter.eq("eventType", HistoricalEvent.EventType.EntitlementRemoved),
Filter.eq("eventType", HistoricalEvent.EventType.EntitlementAdded)));

              startCal.setTime(value);
              endCal.setTime(arguments.get("endDate"));

              int yearDiff = endCal.get(Calendar.YEAR) - startCal.get(Calendar.YEAR);
              int monthDiff = endCal.get(Calendar.MONTH) - startCal.get(Calendar.MONTH);

              int noOfMonths =  yearDiff * 12 + monthDiff;
              log.error(" noOfMonths :"+noOfMonths);

              if(noOfMonths > 12){
              log.error("It is greater than 12 ");
              queryOptions.addFilter(Filter.ge("created", "abc"));
              }else{
              log.error("it is less than 12 ");
              queryOptions.addFilter(Filter.ge("created", value));
              queryOptions.addFilter(Filter.le("created", arguments.get("endDate")));
              log.error("queryOptions :"+queryOptions);
              }
              log.error("last one ");
              return queryOptions;
